var methodIndex = buildMethodIndex()

func buildMethodIndex() map[string]MethodInfo {
	index := make(map[string]MethodInfo, len(methodRegistry))
	for _, info := range methodRegistry {
		if _, exists := index[info.Method]; !exists {
			index[info.Method] = info
		}
	}
	return index
}
